        &lt;div class="container"&gt;
            &lt;div class="filter-group"&gt;
                &lt;button class="filter-btn active" data-filter="all"&gt;All Projects&lt;/button&gt;
                &lt;button class="filter-btn" data-filter="ecology"&gt;🌿 Ecology & Modelling&lt;/button&gt;
                &lt;button class="filter-btn" data-filter="visualisation"&gt;📊 Data Visualisation&lt;/button&gt;
