    &lt;!-- Projects Grid --&gt;
    &lt;section id="projects" class="projects-section"&gt;
        &lt;div class="container"&gt;
            &lt;div class="section-header"&gt;
                &lt;h2&gt;Featured Research Projects&lt;/h2&gt;
                &lt;p&gt;Inspired by ALA Labs — each project includes full code, data sources, and transparent methods&lt;/p&gt;
            &lt;/div&gt;
            &lt;div class="projects-grid" id="projectsGrid"&gt;
                &lt;!-- Project 1: Biodiversity Dashboard --&gt;
                &lt;div class="project-card" data-category="ecology r-project dashboard" data-title="biodiversity trends australia"&gt;
                    &lt;div class="card-badge"&gt;Featured&lt;/div&gt;
                    &lt;div class="card-image"&gt;
                        &lt;img src="assets/images/project-thumb-1.jpg" alt="Biodiversity Dashboard"&gt;
                        &lt;div class="card-overlay"&gt;
                            &lt;a href="projects/biodiversity-dashboard/" class="btn-small"&gt;Live Demo →&lt;/a&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                    &lt;div class="card-content"&gt;
                        &lt;div class="card-meta"&gt;
                            &lt;span class="date"&gt;2024&lt;/span&gt;
                            &lt;span class="tech"&gt;R • flexdashboard • ALA4R&lt;/span&gt;
                        &lt;/div&gt;
                        &lt;h3&gt;Biodiversity Trends in Australia&lt;/h3&gt;
                        &lt;p&gt;Interactive dashboard visualising 50,000+ occurrence records from Atlas of Living Australia. Includes temporal trends, species richness maps, and data quality filters.&lt;/p&gt;
                        &lt;div class="card-links"&gt;
                            &lt;a href="projects/biodiversity-dashboard/" class="link"&gt;View Project →&lt;/a&gt;
                            &lt;a href="https://github.com/[username]/biodiversity-dashboard" class="link-icon"&gt;&lt;i class="fab fa-github"&gt;&lt;/i&gt; Code&lt;/a&gt;
                            &lt;a href="projects/biodiversity-dashboard/methods.pdf" class="link-icon"&gt;&lt;i class="fas fa-file-pdf"&gt;&lt;/i&gt; Methods&lt;/a&gt;
                        &lt;/div&gt;
                        &lt;div class="tags"&gt;
                            &lt;span&gt;Occurrence data&lt;/span&gt;
                            &lt;span&gt;Spatial analysis&lt;/span&gt;
                            &lt;span&gt;Time series&lt;/span&gt;
                            &lt;span&gt;Data cleaning&lt;/span&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                &lt;/div&gt;

                &lt;!-- Project 2: Species Distribution Modelling --&gt;
                &lt;div class="project-card" data-category="ecology python" data-title="maxent species distribution modelling"&gt;
                    &lt;div class="card-image"&gt;
                        &lt;img src="assets/images/project-thumb-2.jpg" alt="Species Distribution Model"&gt;
                        &lt;div class="card-overlay"&gt;
                            &lt;a href="projects/species-modelling/" class="btn-small"&gt;View Report →&lt;/a&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                    &lt;div class="card-content"&gt;
                        &lt;div class="card-meta"&gt;
                            &lt;span class="date"&gt;2024&lt;/span&gt;
                            &lt;span class="tech"&gt;Python • MaxEnt • GeoPandas&lt;/span&gt;
                        &lt;/div&gt;
                        &lt;h3&gt;MaxEnt Species Distribution Modelling&lt;/h3&gt;
                        &lt;p&gt;Presence-only modelling for 5 endangered species. Includes uncertainty quantification, cross-validation, and bias correction for citizen science data.&lt;/p&gt;
                        &lt;div class="card-links"&gt;
                            &lt;a href="projects/species-modelling/" class="link"&gt;View Project →&lt;/a&gt;
                            &lt;a href="https://github.com/[username]/species-modelling" class="link-icon"&gt;&lt;i class="fab fa-github"&gt;&lt;/i&gt; Code&lt;/a&gt;
                            &lt;a href="projects/species-modelling/methods.pdf" class="link-icon"&gt;&lt;i class="fas fa-file-pdf"&gt;&lt;/i&gt; Methods&lt;/a&gt;
                        &lt;/div&gt;
                        &lt;div class="tags"&gt;
                            &lt;span&gt;MaxEnt&lt;/span&gt;
                            &lt;span&gt;SDM&lt;/span&gt;
                            &lt;span&gt;Uncertainty&lt;/span&gt;
                            &lt;span&gt;BIOCLIM&lt;/span&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                &lt;/div&gt;

                &lt;!-- Project 3: GBIF Data Analysis --&gt;
                &lt;div class="project-card" data-category="r-project visualisation" data-title="gbif data cleaning visualization"&gt;
                    &lt;div class="card-image"&gt;
                        &lt;img src="assets/images/project-thumb-3.jpg" alt="GBIF Analysis"&gt;
                        &lt;div class="card-overlay"&gt;
                            &lt;a href="projects/gbif-analysis/" class="btn-small"&gt;View Analysis →&lt;/a&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                    &lt;div class="card-content"&gt;
                        &lt;div class="card-meta"&gt;
                            &lt;span class="date"&gt;2023&lt;/span&gt;
                            &lt;span class="tech"&gt;R • rgbif • ggplot2 • sf&lt;/span&gt;
                        &lt;/div&gt;
                        &lt;h3&gt;GBIF Data Cleaning & Visualisation&lt;/h3&gt;
                        &lt;p&gt;Replicable workflow for downloading, cleaning, and visualising 100,000+ occurrence records. Includes coordinate validation, outlier detection, and publication-ready maps.&lt;/p&gt;
                        &lt;div class="card-links"&gt;
                            &lt;a href="projects/gbif-analysis/" class="link"&gt;View Project →&lt;/a&gt;
                            &lt;a href="https://github.com/[username]/gbif-analysis" class="link-icon"&gt;&lt;i class="fab fa-github"&gt;&lt;/i&gt; Code&lt;/a&gt;
                            &lt;a href="projects/gbif-analysis/workflow.md" class="link-icon"&gt;&lt;i class="fas fa-file-alt"&gt;&lt;/i&gt; Workflow&lt;/a&gt;
                        &lt;/div&gt;
                        &lt;div class="tags"&gt;
                            &lt;span&gt;rgbif&lt;/span&gt;
                            &lt;span&gt;Data validation&lt;/span&gt;
                            &lt;span&gt;ggplot2&lt;/span&gt;
                            &lt;span&gt;Open data&lt;/span&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                &lt;/div&gt;

                &lt;!-- Project 4: Shiny App for Conservation Planning --&gt;
                &lt;div class="project-card" data-category="dashboard r-project ecology" data-title="conservation planning shiny app"&gt;
                    &lt;div class="card-image"&gt;
                        &lt;img src="assets/images/project-thumb-4.jpg" alt="Conservation Planning"&gt;
                        &lt;div class="card-overlay"&gt;
                            &lt;a href="projects/conservation-app/" class="btn-small"&gt;Launch App →&lt;/a&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                    &lt;div class="card-content"&gt;
                        &lt;div class="card-meta"&gt;
                            &lt;span class="date"&gt;2024&lt;/span&gt;
                            &lt;span class="tech"&gt;R Shiny • leaflet • prioritizr&lt;/span&gt;
                        &lt;/div&gt;
                        &lt;h3&gt;Conservation Prioritisation Tool&lt;/h3&gt;
                        &lt;p&gt;Interactive Shiny app for identifying priority conservation areas based on species richness, threat status, and land cost. Includes Marxan connectivity.&lt;/p&gt;
                        &lt;div class="card-links"&gt;
                            &lt;a href="projects/conservation-app/" class="link"&gt;View Project →&lt;/a&gt;
                            &lt;a href="https://github.com/[username]/conservation-app" class="link-icon"&gt;&lt;i class="fab fa-github"&gt;&lt;/i&gt; Code&lt;/a&gt;
                            &lt;a href="projects/conservation-app/methods.pdf" class="link-icon"&gt;&lt;i class="fas fa-file-pdf"&gt;&lt;/i&gt; Methods&lt;/a&gt;
                        &lt;/div&gt;
                        &lt;div class="tags"&gt;
                            &lt;span&gt;Shiny&lt;/span&gt;
                            &lt;span&gt;Conservation&lt;/span&gt;
                            &lt;span&gt;Prioritizr&lt;/span&gt;
                            &lt;span&gt;Interactive&lt;/span&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                &lt;/div&gt;

                &lt;!-- Project 5: Climate Data Analysis --&gt;
                &lt;div class="project-card" data-category="python visualisation" data-title="climate change impact analysis"&gt;
                    &lt;div class="card-image"&gt;
                        &lt;img src="assets/images/project-thumb-5.jpg" alt="Climate Analysis"&gt;
                        &lt;div class="card-overlay"&gt;
                            &lt;a href="projects/climate-analysis/" class="btn-small"&gt;View Analysis →&lt;/a&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                    &lt;div class="card-content"&gt;
                        &lt;div class="card-meta"&gt;
                            &lt;span class="date"&gt;2023&lt;/span&gt;
                            &lt;span class="tech"&gt;Python • xarray • matplotlib&lt;/span&gt;
                        &lt;/div&gt;
                        &lt;h3&gt;Climate Change Impact on Biodiversity&lt;/h3&gt;
                        &lt;p&gt;Analysis of 50 years of climate data and its correlation with species distribution shifts. Includes anomaly detection and future projections under RCP scenarios.&lt;/p&gt;
                        &lt;div class="card-links"&gt;
                            &lt;a href="projects/climate-analysis/" class="link"&gt;View Project →&lt;/a&gt;
                            &lt;a href="https://github.com/[username]/climate-analysis" class="link-icon"&gt;&lt;i class="fab fa-github"&gt;&lt;/i&gt; Code&lt;/a&gt;
                        &lt;/div&gt;
                        &lt;div class="tags"&gt;
                            &lt;span&gt;Climate data&lt;/span&gt;
                            &lt;span&gt;Time series&lt;/span&gt;
                            &lt;span&gt;NetCDF&lt;/span&gt;
                            &lt;span&gt;CMIP6&lt;/span&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                &lt;/div&gt;
            &lt;/div&gt;

            &lt;!-- Load More Button --&gt;
            &lt;div class="load-more"&gt;
                &lt;button id="loadMoreBtn" class="btn-outline"&gt;Load More Projects&lt;/button&gt;
            &lt;/div&gt;
        &lt;/div&gt;
    &lt;/section&gt;

    &lt;!-- Values Section (ALA Labs Style) --&gt;
    &lt;section class="values-section"&gt;
        &lt;div class="container"&gt;
            &lt;h2&gt;Scientific Transparency & Robust Methods&lt;/h2&gt;
            &lt;p class="values-subtitle"&gt;Core principles adopted from ALA Labs&lt;/p&gt;
            &lt;div class="values-grid"&gt;
                &lt;div class="value-card"&gt;
                    &lt;div class="value-icon"&gt;
                        &lt;img src="assets/images/icon-reproducible.svg" alt="Reproducible"&gt;
                    &lt;/div&gt;
                    &lt;h3&gt;Fully Reproducible&lt;/h3&gt;
                    &lt;p&gt;Every analysis includes complete code, session info, and data sources. One-click replication from GitHub.&lt;/p&gt;
                    &lt;div class="value-badge"&gt;✓ Verified 2024&lt;/div&gt;
                &lt;/div&gt;
                &lt;div class="value-card"&gt;
                    &lt;div class="value-icon"&gt;
                        &lt;img src="assets/images/icon-transparent.svg" alt="Transparent"&gt;
                    &lt;/div&gt;
                    &lt;h3&gt;Methods Disclosed&lt;/h3&gt;
                    &lt;p&gt;Strengths AND limitations clearly stated. No hidden assumptions or p-hacking.&lt;/p&gt;
                    &lt;div class="value-badge"&gt;✓ Peer-reviewed workflow&lt;/div&gt;
                &lt;/div&gt;
                &lt;div class="value-card"&gt;
                    &lt;div class="value-icon"&gt;
                        &lt;img src="assets/images/icon-robust.svg" alt="Robust"&gt;
                    &lt;/div&gt;
                    &lt;h3&gt;Robust & Validated&lt;/h3&gt;
                    &lt;p&gt;Cross-validation, sensitivity analysis, and uncertainty quantification for all models.&lt;/p&gt;
                    &lt;div class="value-badge"&gt;✓ Statistical rigor&lt;/div&gt;
                &lt;/div&gt;
                &lt;div class="value-card"&gt;
                    &lt;div class="value-icon"&gt;
                        &lt;i class="fas fa-handshake"&gt;&lt;/i&gt;
                    &lt;/div&gt;
                    &lt;h3&gt;Ethical Data Use&lt;/h3&gt;
                    &lt;p&gt;Acknowledging Traditional Owners, data custodians, and ethical collection protocols.&lt;/p&gt;
                    &lt;div class="value-badge"&gt;✓ Indigenous data sovereignty&lt;/div&gt;
                &lt;/div&gt;
            &lt;/div&gt;
        &lt;/div&gt;
    &lt;/section&gt;

    &lt;!-- Newsletter / Updates Section --&gt;
    &lt;section class="newsletter"&gt;
        &lt;div class="container"&gt;
            &lt;div class="newsletter-content"&gt;
                &lt;h3&gt;Stay Updated on New Projects&lt;/h3&gt;
                &lt;p&gt;Get notified when I publish new research or methods tutorials&lt;/p&gt;
                &lt;form id="newsletterForm" class="newsletter-form"&gt;
                    &lt;input type="email" placeholder="Your email address" required&gt;
                    &lt;button type="submit"&gt;Subscribe →&lt;/button&gt;
                &lt;/form&gt;
                &lt;p class="newsletter-note"&gt;No spam. Unsubscribe anytime.&lt;/p&gt;
            &lt;/div&gt;
        &lt;/div&gt;
    &lt;/section&gt;
&lt;/main&gt;

